using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tool that calls an external API via HttpClient (injected through DI).
/// </summary>
[McpServerToolType]
public class ApiFetchTools(HttpClient httpClient, ILogger<ApiFetchTools> logger)
{
    [McpServerTool, Description("Fetch data from an external API endpoint and return the response body.")]
    public async Task<string> FetchApi(
        [Description("The full URL of the API endpoint to call")] string url,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching API: {Url}", url);
        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

